             """{"title":"What Is Quantum Computing? - IBM","url":"https://www.ibm.com/quantum","snippet":"Quantum computing uses qubits that leverage superposition and entanglement to process information exponentially faster than classical bits for certain problems."}""",
             """{"title":"Quantum Supremacy Achieved - Nature","url":"https://nature.com/articles/quantum-2024","snippet":"Google's latest quantum processor completed a calculation in 200 seconds that would take the fastest supercomputer 10,000 years, demonstrating practical quantum advantage."}""",
             """{"title":"Quantum Error Correction Breakthrough","url":"https://arxiv.org/abs/2024.12345","snippet":"Researchers achieved a logical qubit error rate below the fault-tolerance threshold using a surface code with 1,000 physical qubits, a major milestone for scalable quantum computing."}""",
         ],
         ["artificial intelligence"] =
         [
             """{"title":"The State of AI in 2025 - Stanford HAI","url":"https://hai.stanford.edu/ai-index","snippet":"AI systems now match or exceed human performance on many benchmarks. Foundation models are being adopted across industries, with over 60% of enterprises deploying at least one AI application."}""",
             """{"title":"AI Safety Research Advances","url":"https://deepmind.com/safety","snippet":"New alignment techniques including RLHF and constitutional AI have improved model safety. Researchers report a 40% reduction in harmful outputs compared to previous generations."}""",
             """{"title":"AI Regulation: Global Frameworks","url":"https://reuters.com/tech/ai-regulation","snippet":"The EU AI Act is now in force, establishing risk-based categories. The US and China have also released voluntary guidelines for frontier AI development."}""",
         ],
     };

     // Match on any keyword in the query
     foreach (var (key, value) in results)
     {
         if (query.Contains(key, StringComparison.OrdinalIgnoreCase))
         {
             return $"[{string.Join(",", value)}]";
         }
     }

     // Generic fallback results
     return """[{"title":"Wikipedia","url":"https://en.wikipedia.org","snippet":"Wikipedia is a free encyclopedia with articles on virtually every topic."},{"title":"Research Papers","url":"https://scholar.google.com","snippet":"Google Scholar indexes academic papers, theses, and court opinions."}]""";
 }

 // Note-taking tool captures into the shared notebook
 var takeNoteTool = AIFunctionFactory.Create(
     ([Description("A concise note summarizing a key finding from research")] string note) =>
     {
         notebook.Add(note);
         return $"Note saved. You now have {notebook.Count} note(s).";
     },
     "TakeNote",
     "Save a research note. Use this to record important findings as you research a topic.");

 var readNotesTool = AIFunctionFactory.Create(
     () =>
     {
         if (notebook.Count == 0)
             return "No notes yet.";

         return string.Join("\n", notebook.Notes.Select((n, i) => $"{i + 1}. {n}"));
     },
     "ReadNotes",
     "Read all saved research notes. Use this to review what you've collected before writing a summary.");

 // --- Build the agent ---------------------------------------------------------

 var searchTool = AIFunctionFactory.Create(SearchWeb);

 IChatClient chatClient = new OpenAIClient(apiKey)
     .GetChatClient(modelId)
     .AsIChatClient();

 var agent = new ChatClientAgent(
     chatClient,
     instructions: """
         You are a research assistant. Your job is to research a topic thoroughly and
         produce a well-organized summary.

         Follow this process:
         1. Use SearchWeb to find information about the topic (make 2-3 searches with
            different queries to get broad coverage).
         2. Use TakeNote to save each important finding as a concise note.
         3. Use ReadNotes to review everything you've collected.
         4. Write a final summary that synthesizes all findings into a coherent report
            with sections and key takeaways.

         Be thorough but concise. Cite sources where possible.
         """,
     name: "ResearchAgent",
     description: "An agent that researches topics by searching the web and taking notes.",
     tools: [searchTool, takeNoteTool, readNotesTool]);

 // --- Run the agent -----------------------------------------------------------

 var topic = args.Length > 0
     ? string.Join(' ', args)
     : "quantum computing";

 Console.WriteLine($"🔍 Researching: {topic}\n");

 var runOptions = new ChatClientAgentRunOptions(new ChatOptions
 {
     Temperature = 0f,
     MaxOutputTokens = 2048,
 });

 var session = await agent.CreateSessionAsync();
 var response = await agent.RunAsync(
     $"Research the following topic and provide a comprehensive summary: {topic}",
     session,
     runOptions);

 Console.WriteLine(response.Text);

 // --- Show collected notes ----------------------------------------------------

 if (notebook.Count > 0)
 {
     Console.WriteLine("\n📝 Research Notes Collected:");
     Console.WriteLine(new string('─', 40));
     foreach (var (note, index) in notebook.Notes.Select((n, i) => (n, i)))
     {
         Console.WriteLine($"  {index + 1}. {note}");
     }
 }

 if (response.Usage is { } usage)
 {
     Console.WriteLine($"\n📊 Token usage — Input: {usage.InputTokenCount}, Output: {usage.OutputTokenCount}, Total: {usage.TotalTokenCount}");
 }

 // --- Supporting types --------------------------------------------------------

 /// <summary>Thread-safe notebook for storing research notes.</summary>
 sealed class Notebook
 {
     private readonly List<string> _notes = [];
     private readonly Lock _lock = new();

     public int Count { get { lock (_lock) return _notes.Count; } }

     public IReadOnlyList<string> Notes
     {
         get { lock (_lock) return [.. _notes]; }
     }

     public void Add(string note)
     {
         lock (_lock) _notes.Add(note);
     }
 }

